  ('fire-eq-eng-moex-00458', 'fire-eq-eng', 'fire-eq-eng-moex-110-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編規定，建築物在A層以上，第B層以下之各樓層，應設置緊 急進口。但面臨道路或寬度C公尺以上之通路，且各層之外牆每D公尺設有窗戶或其他開口 者，不在此限。下列敘述何者錯誤？', '["A=2", "B=10", "C=8", "D=10"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:16+00:00", "source_pdf_sha1": "f0272ef09e43", "answer_pdf_sha1": "733f8f7f51f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "110", "exam_name": "110年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
